Here are the public test cases for feature2_1_presence:
{
  "description": "Optional config lookup: present typed values report present with their value; an absent path reports absent rather than raising.",
  "cases": [
    {
      "input": {
        "op": "config_presence",
        "config": {
          "some": {
            "existing": {
              "str": "Existing",
              "int": 42,
              "bool": true,
              "arr": [
                "val1",
                "val2"
              ]
            }
          }
        },
        "type": "string",
        "path": "some.existing.str"
      },
      "expected_output": "state=present\nvalue=Existing\n"
    },
    {
      "input": {
        "op": "config_presence",
        "config": {
          "some": {
            "existing": {
              "str": "Existing",
              "int": 42,
              "bool": true,
              "arr": [
                "val1",
                "val2"
              ]
            }
          }
        },
        "type": "string",
        "path": "some.nonexisting.str"
      },
      "expected_output": "state=absent\n"
    }
  ]
}

